import React from "react";
import './about.css'

function About() {
    return (
      <div id='about-body'>
          <h3>About Me</h3>
          <p>My name is Austin Meyer. I’m 23 years old, and I live in Fort Worth, Texas.
            <br></br>

            I graduated from The University of Texas at Austin in 2021 with a Bachelor of Arts in English. Since then, I've been working full-time while learning web development and UI design. </p>
      </div>
    )
  }

export default About;
